local M={};local function finite(p)return p and p.x==p.x and math.abs(p.x)<math.huge and p.y==p.y and math.abs(p.y)<math.huge end;local function clamp(v,a,b)if v~=v or math.abs(v)==math.huge then return a end return math.min(b,math.max(a,v))end;local function dist(a,b)return math.sqrt((b.x-a.x)^2+(b.y-a.y)^2)end;local function fmt(v)v=math.floor(v*100+.5)/100;if v==0 then return"0"end return(string.format("%.2f",v):gsub("%.?0+$",""))end;local function fp(p)return fmt(p.x).." "..fmt(p.y)end
local function along(a,b,d)local l=dist(a,b)if l==0 then return a end local t=math.min(1,d/l)return{x=a.x+(b.x-a.x)*t,y=a.y+(b.y-a.y)*t}end;local function turn(a,b,c)local ux,uy,vx,vy=b.x-a.x,b.y-a.y,c.x-b.x,c.y-b.y;local ul,vl=math.sqrt(ux^2+uy^2),math.sqrt(vx^2+vy^2)if ul==0 or vl==0 then return 0 end return math.acos(clamp((ux*vx+uy*vy)/(ul*vl),-1,1))*180/math.pi end
function M.build_rounded_drawing_path(input,fs)local p={}for _,v in ipairs(input)do if finite(v)then p[#p+1]=v end end;if#p==0 then return""elseif#p==1 then return"M "..fp(p[1])end;local out={"M "..fp(p[1])};local radius=math.max(12,(fs or 40)*1.25)for i=2,#p-1 do local d=math.min(radius,dist(p[i-1],p[i])*.45,dist(p[i],p[i+1])*.45);out[#out+1]="L "..fp(along(p[i],p[i-1],d)).." Q "..fp(p[i]).." "..fp(along(p[i],p[i+1],d))end;out[#out+1]="L "..fp(p[#p]);return table.concat(out," ")end
function M.create_drawing_path(p,fs)return finite(p)and{points={p},d="M "..fp(p),font_size=fs or 40}or{points={},d="",font_size=fs or 40}end;function M.append_drawing_point(path,p)if not finite(p)or#path.points==0 or dist(path.points[#path.points],p)<3 then return path end;local n={}for i,v in ipairs(path.points)do n[i]=v end;if#n==1 or turn(n[#n-1],n[#n],p)>=18 then n[#n+1]=p else n[#n]=p end;return{points=n,d=M.build_rounded_drawing_path(n,path.font_size),font_size=path.font_size}end;local function drawing(points,fs)local path=nil for _,p in ipairs(points)do if finite(p)then path=path and M.append_drawing_point(path,p)or M.create_drawing_path(p,fs)end end return path and#path.points>=2 and path or nil end
local function perp(p,a,b)local dx,dy=b.x-a.x,b.y-a.y;local l=dx*dx+dy*dy;if l==0 then return dist(p,a)end;local t=clamp(((p.x-a.x)*dx+(p.y-a.y)*dy)/l,0,1)return dist(p,{x=a.x+t*dx,y=a.y+t*dy})end;local function simplify(p,tol)if#p<=2 then return p end;local keep={[1]=true,[#p]=true};local stack={{1,#p}}while#stack>0 do local r=table.remove(stack);local best,index=0,nil for i=r[1]+1,r[2]-1 do local d=perp(p[i],p[r[1]],p[r[2]])if d>best then best,index=d,i end end;if index and best>tol then keep[index]=true;stack[#stack+1]={r[1],index};stack[#stack+1]={index,r[2]}end end;local out={}for i,v in ipairs(p)do if keep[i]then out[#out+1]=v end end return out end
function M.prepare_arc_length_path(input,minimum)minimum=minimum or.5;local valid,filtered={},{}for _,p in ipairs(input)do if finite(p)then valid[#valid+1]=p end end;for _,p in ipairs(valid)do if#filtered==0 or dist(filtered[#filtered],p)>=minimum then filtered[#filtered+1]=p end end;if#valid>0 and#filtered>0 and dist(filtered[#filtered],valid[#valid])>0 then filtered[#filtered+1]=valid[#valid]end;local p=simplify(filtered,math.max(minimum*.5,.1));local path={points=p,segments={},total_length=0}for i=2,#p do local l=dist(p[i-1],p[i])if l>0 then path.segments[#path.segments+1]={a=p[i-1],b=p[i],start=path.total_length,length=l};path.total_length=path.total_length+l end end return path end
local function point_at(path,d)if#path.segments==0 then return{x=0,y=0}end;d=clamp(d,0,path.total_length)for _,s in ipairs(path.segments)do if d<=s.start+s.length then local t=clamp((d-s.start)/s.length,0,1)return{x=s.a.x+(s.b.x-s.a.x)*t,y=s.a.y+(s.b.y-s.a.y)*t}end end return path.segments[#path.segments].b end;function M.sample_at(path,progress,fs)progress=clamp(progress,0,1)if path.total_length<=0 then return{x=0,y=0,angle=0,progress=progress}end;local d=path.total_length*progress;local w=math.max(math.min(math.max((fs or 40)*1.1,.75),path.total_length*.06),.75);local a,b,p=point_at(path,d-w),point_at(path,d+w),point_at(path,d)return{x=p.x,y=p.y,angle=math.atan(b.y-a.y,b.x-a.x),progress=progress}end
function M.stable_repeated_text(text,fs)local phrase=text:match("^%s*(.-)%s*$")if phrase==""then return""end;local chars=utf8 and utf8.len(phrase)or#phrase;local count=math.min(256,math.max(16,math.ceil(20000/math.max(fs,chars*fs*.62))))return(string.rep(phrase.."   ",count):sub(1,-4))end;local function esc(s)return tostring(s):gsub("&","&amp;"):gsub("<","&lt;"):gsub(">","&gt;"):gsub('"',"&quot;"):gsub("'","&apos;")end;local A="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";local function b64(data)local r={}for i=1,#data,3 do local a,b,c=data:byte(i,i+2);b=b or 0;c=c or 0;local n=a*65536+b*256+c;r[#r+1]=A:sub(math.floor(n/262144)%64+1,math.floor(n/262144)%64+1)..A:sub(math.floor(n/4096)%64+1,math.floor(n/4096)%64+1)..(i+1<=#data and A:sub(math.floor(n/64)%64+1,math.floor(n/64)%64+1)or"=")..(i+2<=#data and A:sub(n%64+1,n%64+1)or"=")end return table.concat(r)end
