return'<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="'..fmt(width)..'" height="'..fmt(height)..'" viewBox="0 0 '..fmt(width)..' '..fmt(height)..'"><image width="'..fmt(width)..'" height="'..fmt(height)..'" preserveAspectRatio="xMidYMid slice" href="data:'..mime..';base64,'..b64(bytes)..'"/><defs><path id="brush-path" d="'..esc(path.d)..'"/>'..gradient..shadow..'<mask id="brush-reveal"><rect width="100%" height="100%" fill="black"/><path d="'..esc(path.d)..'" pathLength="1" fill="none" stroke="white" stroke-width="'..fmt(fs*2.4)..'" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="1" stroke-dashoffset="'..fmt(1-reveal)..'"/></mask></defs><g mask="url(#brush-reveal)" opacity="'..fmt(clamp(o.opacity or 1,0,1))..'"'..filter..'><text font-family="'..esc(o.font_family or"Arial, sans-serif")..'" font-size="'..fmt(fs)..'" font-weight="'..esc(o.font_weight or"700")..'" letter-spacing="'..fmt(spacing)..'" fill="'..fill..'" stroke="'..esc(o.stroke_color or"rgba(15,23,42,0.72)")..'" stroke-width="'..fmt(math.max(0,o.stroke_width or 1.5))..'" paint-order="stroke fill"><textPath href="#brush-path" xlink:href="#brush-path" startOffset="0" spacing="exact">'..esc(rendered_text)..'</textPath></text></g></svg>\n'end;return M
